import { encryptSession, decryptSession, hashPassword, verifyPassword, getSession, isAdmin, isSiswa, SessionData } from '@/lib/auth';
import { NextRequest } from 'next/server';

const mockSession: SessionData = {
  userId: '1', username: 'admin', role: 'ADMIN', nama: 'Admin Test',
};

describe('hashPassword / verifyPassword', () => {
  it('should hash and verify password correctly', async () => {
    const hash = await hashPassword('test123');
    expect(hash.startsWith('$2b$')).toBe(true);
    expect(await verifyPassword('test123', hash)).toBe(true);
    expect(await verifyPassword('wrong', hash)).toBe(false);
  });
});

describe('encryptSession', () => {
  it('should produce ROLE.hex format', () => {
    expect(encryptSession(mockSession)).toMatch(/^ADMIN\.[a-f0-9]+$/);
  });
  it('should handle GURU and SISWA roles', () => {
    expect(encryptSession({ ...mockSession, role: 'GURU' })).toMatch(/^GURU\./);
    expect(encryptSession({ ...mockSession, role: 'SISWA', nis: '123' })).toMatch(/^SISWA\./);
  });
});

describe('decryptSession', () => {
  it('should decrypt valid token', () => {
    const token = encryptSession(mockSession);
    expect(decryptSession(token)).toEqual(mockSession);
  });
  it('should return null for corrupted hex', () => {
    expect(decryptSession('ADMIN.zzzzinvalidhex')).toBeNull();
  });
  it('should return null when role prefix mismatches decrypted role', () => {
    const tampered = encryptSession(mockSession).replace('ADMIN', 'GURU');
    expect(decryptSession(tampered)).toBeNull();
  });
  it('should return null for malformed token (no dot)', () => {
    expect(decryptSession('foobar')).toBeNull();
  });
  it('should return null for empty string', () => {
    expect(decryptSession('')).toBeNull();
  });
});

describe('getSession', () => {
  function mockReq(cookie?: string): NextRequest {
    return { cookies: { get: () => cookie ? { name: 'session_token', value: cookie } : undefined } } as any;
  }
  it('should return session for valid cookie', () => {
    const token = encryptSession(mockSession);
    expect(getSession(mockReq(token))?.username).toBe('admin');
  });
  it('should return null when no cookie', () => {
    expect(getSession(mockReq())).toBeNull();
  });
});

describe('isAdmin / isSiswa', () => {
  function mockReq(role: string): NextRequest {
    const token = encryptSession({ ...mockSession, role: role as any });
    return { cookies: { get: () => ({ name: 'session_token', value: token }) } } as any;
  }
  it('isAdmin returns true for ADMIN role', () => {
    expect(isAdmin(mockReq('ADMIN'))).toBe(true);
    expect(isAdmin(mockReq('GURU'))).toBe(false);
  });
  it('isSiswa returns true for SISWA role', () => {
    expect(isSiswa(mockReq('SISWA'))).toBe(true);
    expect(isSiswa(mockReq('ADMIN'))).toBe(false);
  });
});
