describe('sendWhatsAppNotification', () => {
  const basePayload = {
    namaSiswa: 'Budi', nis: '12345', tanggal: '2024-06-15',
    status: 'ALPA' as const, whatsappOrangTua: '+628123456789',
  };

  beforeEach(() => {
    delete process.env.WA_API_TOKEN;
    delete process.env.WA_GATEWAY_URL;
  });

  it('should return error when WA_API_TOKEN not configured', async () => {
    const result = await sendWhatsAppNotification(basePayload);
    expect(result.success).toBe(false);
    expect(result.error).toContain('belum dikonfigurasi');
  });

  it('should return error when no phone number', async () => {
    const result = await sendWhatsAppNotification({ ...basePayload, whatsappOrangTua: '' });
    expect(result.success).toBe(false);
    expect(result.error).toContain('tidak diisi');
  });

  it('should handle API gateway error', async () => {
    process.env.WA_API_TOKEN = 'valid-token';
    process.env.WA_GATEWAY_URL = 'https://httpbin.org/status/500';
    const result = await sendWhatsAppNotification(basePayload);
    expect(result.success).toBe(false);
  });

  it('should construct correct request body for ALPA', async () => {
    process.env.WA_API_TOKEN = 'test-token';
    process.env.WA_GATEWAY_URL = 'https://httpbin.org/post';
    // Mock fetch to capture body shape
    const original = global.fetch;
    let captured: any = null;
    global.fetch = async (url: any, opts: any) => {
      captured = JSON.parse(opts.body);
      return { ok: true, json: async () => ({ id: 'msg_1' }) } as Response;
    };
    await sendWhatsAppNotification(basePayload);
    expect(captured.target).toBe('+628123456789');
    expect(captured.message).toContain('ALPA');
    expect(captured.countryCode).toBe('62');
    global.fetch = original;
  });
});
