/**
 * Integration test skeleton for POST /api/auth/login
 */
import { POST } from '@/app/api/auth/login/route';
import { NextRequest } from 'next/server';

// Mock prisma & bcrypt before import
jest.mock('@/lib/prisma', () => ({
  prisma: {
    admin: { findUnique: jest.fn() },
    guru: { findUnique: jest.fn() },
    siswa: { findUnique: jest.fn() },
  },
}));

describe('POST /api/auth/login', () => {
  function createReq(body: any): NextRequest {
    return {
      json: async () => body,
      headers: new Map([['x-forwarded-for', '127.0.0.1']]),
      url: 'http://localhost:3000/api/auth/login',
    } as unknown as NextRequest;
  }

  it('should reject empty body', async () => {
    const res = await POST(createReq({}));
    expect(res.status).toBe(400);
    const data = await res.json();
    expect(data.error).toContain('wajib diisi');
  });

  it('should reject short username', async () => {
    const res = await POST(createReq({ username: 'ab', password: '123456' }));
    expect(res.status).toBe(400);
  });

  it('should reject short password', async () => {
    const res = await POST(createReq({ username: 'admin', password: '12345' }));
    expect(res.status).toBe(400);
  });

  it('should reject invalid credentials', async () => {
    const { prisma } = require('@/lib/prisma');
    prisma.admin.findUnique.mockResolvedValue(null);
    prisma.guru.findUnique.mockResolvedValue(null);
    prisma.siswa.findUnique.mockResolvedValue(null);

    const res = await POST(createReq({ username: 'nonexistent', password: '123456' }));
    expect(res.status).toBe(401);
  });

  it('should return 429 after 5+ attempts from same IP', async () => {
    // Rate limit test
    const { prisma } = require('@/lib/prisma');
    prisma.admin.findUnique.mockResolvedValue(null);
    prisma.guru.findUnique.mockResolvedValue(null);
    prisma.siswa.findUnique.mockResolvedValue(null);

    for (let i = 0; i < 5; i++) {
      await POST(createReq({ username: 'user', password: 'wrongpass' }));
    }
    const res = await POST(createReq({ username: 'user', password: 'wrongpass' }));
    expect(res.status).toBe(429);
  });
});
